				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"label": ">primary | seriesByName(\"index\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"statics": [],
				"value": ">primary | seriesByName(\"index\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			},
			"dataSources": {
				"primary": "ds_Gbyds2zV"
			},
			"options": {
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"selectFirstSearchResult": true,
				"token": "token_index"
			},
			"title": "Index",
			"type": "input.multiselect"
		},
		"input_global_trp": {
			"options": {
