		"ds_Xp5jtgpY": {
			"name": "Windows Users Overview",
			"options": {
				"query": "index IN ($token_index$) host IN ($token_host$) source=\"windows:hklm\" registry.category=\"User Accounts\" registry.comment=\"User accounts in SAM hive\"\n| rex field=registry.value_data \"Username:\\s+(?<username>\\S+)\\s+Id:\\s+(?<rid>\\d+)\"\n| eval data_source=\"SAM\"\n| table index host username rid data_source\n| append\n    [search index IN ($token_index$) host IN ($token_host$) source=\"windows:hklm\" registry.category=\"User Accounts\" registry.comment=\"User accounts in SOFTWARE hive\"\n    | rex field=registry.value_data \"KeyName:\\s+(?<sid>S-[\\d-]+)\"\n    | rex field=registry.value_data3 \"ProfileImagePath:\\s+.*\\\\\\\\(?<username>[^\\\\\\\\]+)$\"\n    | eval data_source=\"SOFTWARE\"\n    | table index host username sid data_source]\n| stats latest(rid) AS rid latest(sid) AS sid by index, host, username\n| rex field=sid \"^(?<sid_base>S-1-5-21-\\d+-\\d+-\\d+)-(?<sid_rid>\\d+)$\"\n| eventstats values(eval(if(isnotnull(rid) AND isnotnull(sid) AND sid_rid=rid, sid_base, null()))) AS local_sid_base by index, host\n| eval rid=coalesce(rid, sid_rid)\n| eval origin=case(\n    match(sid,\"^S-1-5-(18|19|20)$\"), \"System\",\n    sid_base=local_sid_base, \"Local\",\n    isnotnull(sid_base), \"Domain\",\n    isnotnull(rid) AND isnull(sid), \"Local (SAM only)\",\n    1=1, \"Unknown\")\n| eventstats dc(host) AS total_hosts\n| eventstats dc(host) AS user_host_count by username, origin\n| eval is_anomaly=if(user_host_count<total_hosts, 1, 0)\n| eval user_display=case(\n    is_anomaly=1 AND origin=\"System\", \"️⚠️ \".username.\" (\".user_host_count.\"/\".total_hosts.\")\",\n    is_anomaly=1 AND (origin=\"Local\" OR origin=\"Local (SAM only)\"), \"⚠️ \".username.\" (\".user_host_count.\"/\".total_hosts.\")\",\n    is_anomaly=1 AND origin=\"Domain\", \"⚠️ \".username.\" (\".user_host_count.\"/\".total_hosts.\")\",\n    origin=\"System\", username,\n    origin=\"Local\" OR origin=\"Local (SAM only)\", username,\n    origin=\"Domain\", username,\n    1=1, \"❓ \".username)\n| stats values(eval(if(origin=\"Local\" OR origin=\"Local (SAM only)\", user_display, null()))) AS local_users values(eval(if(origin=\"Domain\", user_display, null()))) AS domain_users values(eval(if(origin=\"System\", user_display, null()))) AS system_users by index, host\n| eval local_users=mvjoin(local_users, \"\n\")\n| eval domain_users=mvjoin(domain_users, \"\n\")\n| eval system_users=mvjoin(system_users, \"\n\")\n| table index host local_users domain_users system_users",
				"queryParameters": {
					"earliest": "0",
					"latest": ""
				}
			},
			"type": "ds.search"
		},
		"ds_YmhyTr2N": {
			"name": "assets_collect_info",
			"options": {
				"query": "search index IN ($token_index$) host IN ($token_host$) source=\"collect:info\"\n| eval size_num=tonumber(size)\n| rex field=name \"^[^_]+_[^_]+_[^_]+_(?<archive_type>[^.]+)\\.7z$\"\n| eval size_human=case(\n    size_num>=1024*1024*1024, tostring(round(size_num/1024/1024/1024, 3)).\" GB\",\n    size_num>=1024*1024, tostring(round(size_num/1024/1024, 3)).\" MB\",\n    size_num>=1024, tostring(round(size_num/1024, 3)).\" KB\",\n    isnotnull(size_num), tostring(size_num).\" B\"\n)\n| eventstats dc(archive_type) as total_archive_type_count values(archive_type) as all_archive_types\n| stats dc(archive_type) as host_archive_type_count\n        first(total_archive_type_count) as total_archive_type_count\n        values(all_archive_types) as all_archive_types\n        values(archive_type) as host_archive_types\n        values(name) as name\n        values(sha1) as sha1\n        values(size_human) as size\n        sum(size_num) as total_size_num\n        by host\n| eval missing_archive_type=mvmap(all_archive_types, if(isnull(mvfind(host_archive_types, \"^\".all_archive_types.\"$\")), all_archive_types, null()))\n| eval total_size=case(\n    total_size_num>=1024*1024*1024, tostring(round(total_size_num/1024/1024/1024, 3)).\" GB\",\n    total_size_num>=1024*1024, tostring(round(total_size_num/1024/1024, 3)).\" MB\",\n    total_size_num>=1024, tostring(round(total_size_num/1024, 3)).\" KB\",\n    isnotnull(total_size_num), tostring(total_size_num).\" B\"\n)\n| eval coverage=host_archive_type_count.\"/\".total_archive_type_count\n| sort 0 host_archive_type_count host\n| table host coverage missing_archive_type name sha1 size total_size",
				"queryParameters": {
					"earliest": "0",
					"latest": ""
				}
			},
			"type": "ds.search"
		},
		"ds_ZNl136kr": {
			"name": "data_sources_script",
			"options": {
				"query": "| tstats count WHERE index IN ($token_index$) host IN ($token_host$) by index, host, source, sourcefile\n| eval actual = count - 1\n| fields - count\n| append\n    [search index IN ($token_index$) host IN ($token_host$) event_type=\"ingestion_metadata\"\n    | table index host source sourcefile expected_event_count]\n| stats first(actual) AS actual first(expected_event_count) AS expected by index, host, source, sourcefile\n| eval expected = tonumber(expected),\n       delta = actual - expected,\n       file_ok = if(actual=expected, 1, 0)\n| stats \n    sum(expected) AS expected\n    sum(actual) AS actual\n    sum(delta) AS delta\n    sum(file_ok) AS files_ok\n    count AS files_total\n    by index, host, source\n| eval status = case(\n    isnull(expected), \"⚠️ No metadata\",\n    actual=expected, \"✅ Complete (\".files_total.\" files)\",\n    actual < expected, \"❌ Missing \".abs(delta).\" events (\".files_ok.\"/\".files_total.\" files OK)\",\n    actual > expected, \"⚠️ Extra \".delta.\" events (\".files_ok.\"/\".files_total.\" files OK)\")\n| eval _complete = if(match(status, \"^✅\"), 1, 0)\n| eventstats min(_complete) AS _all_complete\n| where \"$show_all_token$\"=\"true\" OR _complete=0 OR _all_complete=1\n| eval source = if(_all_complete=1 AND \"$show_all_token$\"=\"false\", \"✅ All sources complete\", source),\n       expected = if(_all_complete=1 AND \"$show_all_token$\"=\"false\", null(), expected),\n       actual = if(_all_complete=1 AND \"$show_all_token$\"=\"false\", null(), actual),\n       delta = if(_all_complete=1 AND \"$show_all_token$\"=\"false\", null(), delta),\n       status = if(_all_complete=1 AND \"$show_all_token$\"=\"false\", null(), status)\n| dedup source\n| fields - _complete, _all_complete, files_ok, files_total\n| sort - expected\n| rename source as Source\n| table index Source expected actual delta status",
				"queryParameters": {
					"earliest": "0",
					"latest": ""
				}
			},
			"type": "ds.search"
		},
		"ds_wWg0wvzF": {
			"name": "assets_orc_outcome_present",
			"options": {
				"query": "| tstats count WHERE index IN ($token_index$) host IN ($token_host$) source=\"windows:orc_outcome\" \n| where count=0 \n| eval message=\"⚠️ No windows:orc_outcome source found\"",
				"queryParameters": {
					"earliest": "0",
					"latest": ""
				}
			},
			"type": "ds.search"
		},
		"ds_x5iDWP6h": {
			"name": "data_sources_evtx_retention",
			"options": {
				"query": "index IN ($token_index$) host IN ($token_host$) source=windows:evtx* NOT event_type=\"ingestion_metadata\"\n [| makeresults\n     | eval eid=\"4688,4698,4697,4657,4663,5140,1,3,10,11,13,22,4104\"\n     | makemv eid delim=\",\"\n     | mvexpand eid\n     | rename eid AS event.id\n     | where \"$token_evtx_view$\"=\"eventid\"\n     | table event.id\n     | append [| makeresults | eval event.id=\"*\" | where \"$token_evtx_view$\"=\"channel\" | table event.id]]\n| eval eid = 'event.id'\n| eval group_key = case(\n    \"$token_evtx_view$\"=\"eventid\", eid,\n    1=1, source)\n| eval label = case(\n    \"$token_evtx_view$\"=\"channel\", source,\n    eid=\"4688\", \"4688 — Process Creation + CmdLine\",\n    eid=\"4697\", \"4697 — Service Installed\",\n    eid=\"4698\", \"4698 — Scheduled Task Created\",\n    eid=\"4657\", \"4657 — Registry Value Modified\",\n    eid=\"4663\", \"4663 — Object Access Attempt\",\n    eid=\"5140\", \"5140 — Network Share Accessed\",\n    eid=\"1\", \"1 — Sysmon Process Create\",\n    eid=\"3\", \"3 — Sysmon Network Connection\",\n    eid=\"10\", \"10 — Sysmon Process Access\",\n    eid=\"11\", \"11 — Sysmon File Create\",\n    eid=\"13\", \"13 — Sysmon Registry Value Set\",\n    eid=\"22\", \"22 — Sysmon DNS Query\",\n    eid=\"4104\", \"4104 — PowerShell Script Block\",\n    1=1, group_key)\n| stats count min(_time) AS earliest max(_time) AS latest by index, host, group_key, label\n| eval earliest_time = strftime(earliest, \"%Y-%m-%d %H:%M:%S\"),\n       latest_time = strftime(latest, \"%Y-%m-%d %H:%M:%S\"),\n       span_days = round((latest - earliest) / 86400, 1)\n| sort index host - count\n| rename host as Endpoint, label as Channel, count as Events, span_days as \"Retention (days)\", earliest_time as \"Earliest Event\", latest_time as \"Latest Event\"\n| table index Endpoint Channel Events \"Earliest Event\" \"Latest Event\" \"Retention (days)\"",
				"queryParameters": {
					"earliest": "0",
					"latest": ""
				}
			},
			"type": "ds.search"
		}
	},
